ALTER TABLE evaluation_contexts ADD COLUMN IF NOT EXISTS rationale TEXT;                            -- Why this instant was chosen.
ALTER TABLE evaluation_contexts ADD COLUMN IF NOT EXISTS semantic_type_iri TEXT;                    -- Extension class IRI.
