-- ----------------------------------------------------------------------------
-- Steps: Version-scoped units of work. Atomic steps map to pplan:Step; composite steps map to pplan:MultiStep. The specification is never conflated with execution.
-- ----------------------------------------------------------------------------
CREATE TABLE IF NOT EXISTS steps (
  step_id                             TEXT                 PRIMARY KEY          -- Stored logical identifier for one Steps row.
);
ALTER TABLE steps ADD COLUMN IF NOT EXISTS procedure_version TEXT;                                  -- Procedure version containing the step; maps to pko:hasStep/pplan:isStepOfPlan.
