ALTER TABLE steps ADD COLUMN IF NOT EXISTS step_kind TEXT;                                          -- Atomic or MultiStep.
ALTER TABLE steps ADD COLUMN IF NOT EXISTS assigned_role TEXT;                                      -- Role responsible for the step.
ALTER TABLE steps ADD COLUMN IF NOT EXISTS instruction TEXT;                                        -- Normative step instruction.
ALTER TABLE steps ADD COLUMN IF NOT EXISTS expected_duration_minutes INTEGER;                       -- Expected duration represented as an OWL-Time duration in semantic projections.
ALTER TABLE steps ADD COLUMN IF NOT EXISTS expertise_level TEXT;                                    -- PKO expertise level: Junior, Senior, Expert, or Master.
ALTER TABLE steps ADD COLUMN IF NOT EXISTS requires_human_confirmation BOOLEAN;                     -- TRUE when a human must confirm the step; maps to pko:wasConfirmedBy at execution.
ALTER TABLE steps ADD COLUMN IF NOT EXISTS control_kind TEXT;                                       -- What kind of control this step is: Preparation, Approval, LegalReview, Verification, Extraction, Publication, Retrospective, or None. That policy-04 is a legal review is a property OF policy-04, not of a formula that happens to name it; storing it as data makes downstream predicates portable to procedures that do not exist yet.
ALTER TABLE steps ADD COLUMN IF NOT EXISTS semantic_type_iri TEXT;                                  -- Exact P-Plan class IRI.
COMMENT ON TABLE steps IS 'Version-scoped units of work. Atomic steps map to pplan:Step; composite steps map to pplan:MultiStep. The specification is never conflated with execution.';
