ALTER TABLE step_transitions ADD COLUMN IF NOT EXISTS semantic_type_iri TEXT;                       -- Exact PKO class IRI.
COMMENT ON TABLE step_transitions IS 'Directed control-flow edges represented as first-class pko:Transition instances with fromStep/toStep and next/alternative/fallback semantics.';
