ALTER TABLE knowledge_fragments ADD COLUMN IF NOT EXISTS valid_to TIMESTAMPTZ;                      -- End of the fragment's valid-time interval.
ALTER TABLE knowledge_fragments ADD COLUMN IF NOT EXISTS status TEXT;                               -- Draft, Reviewed, Approved, Rejected, or Superseded.
ALTER TABLE knowledge_fragments ADD COLUMN IF NOT EXISTS owner_role TEXT;                           -- Role accountable for maintaining the fragment.
ALTER TABLE knowledge_fragments ADD COLUMN IF NOT EXISTS evaluation_context TEXT;                   -- The evaluation context this row's time-dependent witnesses are judged under.
ALTER TABLE knowledge_fragments ADD COLUMN IF NOT EXISTS last_reviewed_at TIMESTAMPTZ;              -- When this fragment was last actually reviewed and reaffirmed by its owning role. Null when it has never been reviewed since authoring. IsOverdueForReview infers recency from ValidFrom, which records when the claim became TRUE, not when anyone last looked at it. Those are different events, and the inference is deliberately left in place under its own name rather than silently rewritten to fall back on this column.
ALTER TABLE knowledge_fragments ADD COLUMN IF NOT EXISTS semantic_type_iri TEXT;                    -- Extension class IRI.
COMMENT ON TABLE knowledge_fragments IS 'Explicit records of tacit, implicit, explicit, and situated procedural knowledge. This is an ERB-PKO extension represented as provenance-bearing dcat:Resource instances.';
