  change_request_id                   TEXT                 PRIMARY KEY          -- Stored logical identifier for one ChangeRequests row.
);
ALTER TABLE change_requests ADD COLUMN IF NOT EXISTS procedure_version TEXT;                        -- Procedure version affected.
ALTER TABLE change_requests ADD COLUMN IF NOT EXISTS title TEXT;                                    -- Change title.
ALTER TABLE change_requests ADD COLUMN IF NOT EXISTS change_kind TEXT;                              -- Defect, Enhancement, NewRequirement, DataOperation, or BreakingChange.
ALTER TABLE change_requests ADD COLUMN IF NOT EXISTS status TEXT;                                   -- Draft, UnderReview, Approved, Rejected, Implemented, or Closed.
ALTER TABLE change_requests ADD COLUMN IF NOT EXISTS requested_by_agent TEXT;                       -- Agent requesting the change.
