ALTER TABLE change_requests ADD COLUMN IF NOT EXISTS implemented_at TIMESTAMPTZ;                    -- When the approved change was actually applied to the procedure version. Null until it lands. Distinct from DecidedAt, which records only that the authority ruled. Approval and implementation are separate events; conflating them is what left IsOpen with no terminal state.
