);
ALTER TABLE communication_policies ADD COLUMN IF NOT EXISTS procedure_version TEXT;                 -- Procedure version governing the channel.
ALTER TABLE communication_policies ADD COLUMN IF NOT EXISTS channel TEXT;                           -- Email, SMS, Push, Postal, or another declared channel.
ALTER TABLE communication_policies ADD COLUMN IF NOT EXISTS audience_rule TEXT;                     -- Rule that identifies eligible recipients.
ALTER TABLE communication_policies ADD COLUMN IF NOT EXISTS consent_required BOOLEAN;               -- Whether active consent is required.
ALTER TABLE communication_policies ADD COLUMN IF NOT EXISTS quiet_hours_start DATE;                 -- Recipient-local quiet-hours start.
ALTER TABLE communication_policies ADD COLUMN IF NOT EXISTS quiet_hours_end DATE;                   -- Recipient-local quiet-hours end.
ALTER TABLE communication_policies ADD COLUMN IF NOT EXISTS max_message_length INTEGER;             -- Maximum message length for one unit.
ALTER TABLE communication_policies ADD COLUMN IF NOT EXISTS max_segments INTEGER;                   -- Maximum number of channel segments.
ALTER TABLE communication_policies ADD COLUMN IF NOT EXISTS retention_days INTEGER;                 -- Retention period for rendered messages and delivery records.
ALTER TABLE communication_policies ADD COLUMN IF NOT EXISTS approval_role TEXT;                     -- Role approving the channel policy.
ALTER TABLE communication_policies ADD COLUMN IF NOT EXISTS required_content TEXT;                  -- Content that every message must include.
ALTER TABLE communication_policies ADD COLUMN IF NOT EXISTS authority_statement TEXT;               -- Which artifact is authoritative.
ALTER TABLE communication_policies ADD COLUMN IF NOT EXISTS status TEXT;                            -- Draft, Active, Suspended, or Retired.
ALTER TABLE communication_policies ADD COLUMN IF NOT EXISTS quiet_hours_start_hour INTEGER;         -- The hour (0-23) at which the quiet window opens. Stored rather than parsed from QuietHoursStart: VALUE(LEFT(...)) does not translate — the transpiler casts the "20:00" string to a timestamp and the view errors. The sending system already knows this number, so modeling it as a parse would dress a broken derivation up as a rule.
ALTER TABLE communication_policies ADD COLUMN IF NOT EXISTS quiet_hours_end_hour INTEGER;           -- Numeric hour 0-23 at which quiet hours end. Seeded 8 for comm-sms-policy, 0 for comm-email-policy.
ALTER TABLE communication_policies ADD COLUMN IF NOT EXISTS required_opt_out_phrase TEXT;           -- The exact opt-out phrase every message on this channel must contain. Seeded 'Reply STOP' for comm-sms-policy, empty string for comm-email-policy.
ALTER TABLE communication_policies ADD COLUMN IF NOT EXISTS semantic_type_iri TEXT;                 -- ODRL Policy class IRI.
