-- ----------------------------------------------------------------------------
-- WitnessLoops: One row per role-question expansion loop. Each loop poses questions that only became askable because of the previous loop's predicates.
-- ----------------------------------------------------------------------------
CREATE TABLE IF NOT EXISTS witness_loops (
  witness_loop_id                     TEXT                 PRIMARY KEY          -- Stored logical identifier for one WitnessLoops row.
);
ALTER TABLE witness_loops ADD COLUMN IF NOT EXISTS loop_number NUMERIC;                             -- Ordinal of this expansion loop. Loop 1 is the founding set of role questions.
ALTER TABLE witness_loops ADD COLUMN IF NOT EXISTS title TEXT;                                      -- Short title for what this loop set out to make askable.
ALTER TABLE witness_loops ADD COLUMN IF NOT EXISTS premise TEXT;                                    -- Why this loop's questions became askable. For loop N>1 this names the loop N-1 predicates that made them possible.
ALTER TABLE witness_loops ADD COLUMN IF NOT EXISTS started_at TIMESTAMPTZ;                          -- Time this loop began.
ALTER TABLE witness_loops ADD COLUMN IF NOT EXISTS completed_at TIMESTAMPTZ;                        -- Time this loop was committed. Null while in progress.
ALTER TABLE witness_loops ADD COLUMN IF NOT EXISTS fields_after NUMERIC;                            -- Total fields in the rulebook after this loop completed.
ALTER TABLE witness_loops ADD COLUMN IF NOT EXISTS derived_after NUMERIC;                           -- Derived fields after this loop completed.
ALTER TABLE witness_loops ADD COLUMN IF NOT EXISTS witnessed_after NUMERIC;                         -- Fields invented for a role question after this loop completed.
ALTER TABLE witness_loops ADD COLUMN IF NOT EXISTS semantic_type_iri TEXT;                          -- Extension class IRI.
COMMENT ON TABLE witness_loops IS 'One row per role-question expansion loop. Each loop poses questions that only became askable because of the previous loop''s predicates.';
COMMENT ON COLUMN witness_loops.witness_loop_id IS 'Stored logical identifier for one WitnessLoops row.';
COMMENT ON COLUMN witness_loops.loop_number IS 'Ordinal of this expansion loop. Loop 1 is the founding set of role questions.';
COMMENT ON COLUMN witness_loops.title IS 'Short title for what this loop set out to make askable.';
COMMENT ON COLUMN witness_loops.premise IS 'Why this loop''s questions became askable. For loop N>1 this names the loop N-1 predicates that made them possible.';
COMMENT ON COLUMN witness_loops.started_at IS 'Time this loop began.';
COMMENT ON COLUMN witness_loops.completed_at IS 'Time this loop was committed. Null while in progress.';
COMMENT ON COLUMN witness_loops.fields_after IS 'Total fields in the rulebook after this loop completed.';
COMMENT ON COLUMN witness_loops.derived_after IS 'Derived fields after this loop completed.';
COMMENT ON COLUMN witness_loops.witnessed_after IS 'Fields invented for a role question after this loop completed.';
COMMENT ON COLUMN witness_loops.semantic_type_iri IS 'Extension class IRI.';

-- ----------------------------------------------------------------------------
-- RoleQuestions: One row per question a named role wants answered. Every invented predicate in this rulebook traces back to one of these.
-- ----------------------------------------------------------------------------
CREATE TABLE IF NOT EXISTS role_questions (
  role_question_id                    TEXT                 PRIMARY KEY          -- Stored logical identifier for one RoleQuestions row.
);
ALTER TABLE role_questions ADD COLUMN IF NOT EXISTS asking_role TEXT;                               -- The role that wants this question answered.
ALTER TABLE role_questions ADD COLUMN IF NOT EXISTS witness_loop TEXT;                              -- The expansion loop in which this question was posed.
ALTER TABLE role_questions ADD COLUMN IF NOT EXISTS question_text TEXT;                             -- The question in the role's own words.
ALTER TABLE role_questions ADD COLUMN IF NOT EXISTS why_it_matters TEXT;                            -- What goes wrong in the real world when this question cannot be answered.
ALTER TABLE role_questions ADD COLUMN IF NOT EXISTS answerable_before BOOLEAN;                      -- TRUE if the model could already answer this before its loop ran. FALSE means the loop had to invent predicates for it.
ALTER TABLE role_questions ADD COLUMN IF NOT EXISTS witnessed_answer TEXT;                          -- The current reading of this question's predicates, extracted from the substrate after the loop ran: which witness columns fire, on how many rows out of how many. Written by tools/extract_computed_answers.py from values Postgres computed — never recomputed in Python. This is what lets a later loop plan against materialized answers instead of imagined ones.
ALTER TABLE role_questions ADD COLUMN IF NOT EXISTS semantic_type_iri TEXT;                         -- Extension class IRI.
COMMENT ON TABLE role_questions IS 'One row per question a named role wants answered. Every invented predicate in this rulebook traces back to one of these.';
COMMENT ON COLUMN role_questions.role_question_id IS 'Stored logical identifier for one RoleQuestions row.';
COMMENT ON COLUMN role_questions.asking_role IS 'The role that wants this question answered.';
COMMENT ON COLUMN role_questions.witness_loop IS 'The expansion loop in which this question was posed.';
COMMENT ON COLUMN role_questions.question_text IS 'The question in the role''s own words.';
COMMENT ON COLUMN role_questions.why_it_matters IS 'What goes wrong in the real world when this question cannot be answered.';
COMMENT ON COLUMN role_questions.answerable_before IS 'TRUE if the model could already answer this before its loop ran. FALSE means the loop had to invent predicates for it.';
COMMENT ON COLUMN role_questions.witnessed_answer IS 'The current reading of this question''s predicates, extracted from the substrate after the loop ran: which witness columns fire, on how many rows out of how many. Written by tools/extract_computed_answers.py from values Postgres computed — never recomputed in Python. This is what lets a later loop plan against materialized answers instead of imagined ones.';
COMMENT ON COLUMN role_questions.semantic_type_iri IS 'Extension class IRI.';

