-- ----------------------------------------------------------------------------
-- ObservedTransitions: The proxy above cannot tell a walked fallback from a happy-path step that happens to share an endpoint. PKO models Transition as a first-class thing; its execution counterpart is missing. Without a table that records WHICH transition a step execution arrived by, 'has this fallback ever been walked' is permanently unanswerable rather than merely unanswered. This is an extension (urn:effortless:pko-extension#ObservedTransition), not a native PKO term.
-- ----------------------------------------------------------------------------
CREATE TABLE IF NOT EXISTS observed_transitions (
  observed_transition_id              TEXT                 PRIMARY KEY          -- Stored logical identifier for one ObservedTransitions row.
);
ALTER TABLE observed_transitions ADD COLUMN IF NOT EXISTS procedure_execution TEXT;                 -- The procedure execution during which this transition was traversed.
ALTER TABLE observed_transitions ADD COLUMN IF NOT EXISTS step_transition TEXT;                     -- The specification-level transition that was actually taken.
ALTER TABLE observed_transitions ADD COLUMN IF NOT EXISTS arriving_step_execution TEXT;             -- The step execution that this traversal produced.
ALTER TABLE observed_transitions ADD COLUMN IF NOT EXISTS observed_at TIMESTAMPTZ;                  -- When the traversal occurred.
ALTER TABLE observed_transitions ADD COLUMN IF NOT EXISTS trigger_reason TEXT;                      -- Why this path rather than the default was taken.
ALTER TABLE observed_transitions ADD COLUMN IF NOT EXISTS semantic_type_iri TEXT;                   -- Extension class IRI.
COMMENT ON TABLE observed_transitions IS 'The proxy above cannot tell a walked fallback from a happy-path step that happens to share an endpoint. PKO models Transition as a first-class thing; its execution counterpart is missing. Without a table that records WHICH transition a step execution arrived by, ''has this fallback ever been walked'' is permanently unanswerable rather than merely unanswered. This is an extension (urn:effortless:pko-extension#ObservedTransition), not a native PKO term.';
COMMENT ON COLUMN observed_transitions.observed_transition_id IS 'Stored logical identifier for one ObservedTransitions row.';
COMMENT ON COLUMN observed_transitions.procedure_execution IS 'The procedure execution during which this transition was traversed.';
COMMENT ON COLUMN observed_transitions.step_transition IS 'The specification-level transition that was actually taken.';
COMMENT ON COLUMN observed_transitions.arriving_step_execution IS 'The step execution that this traversal produced.';
COMMENT ON COLUMN observed_transitions.observed_at IS 'When the traversal occurred.';
COMMENT ON COLUMN observed_transitions.trigger_reason IS 'Why this path rather than the default was taken.';
COMMENT ON COLUMN observed_transitions.semantic_type_iri IS 'Extension class IRI.';

