-- ----------------------------------------------------------------------------
-- DeliveredCommunications: Everything above is a proxy for the real question, which is instance-level: THIS message, to THIS recipient, rendered from THIS template, authorized by THIS approval. The model has MessageTemplates and CommunicationPolicies as specifications and no record of a single thing ever sent. Without an instance table, 'can I show that what was sent matched what I approved' is permanently unanswerable rather than merely unanswered — and it is the question a disputing employee actually asks. Extension term (urn:effortless:pko-extension#DeliveredCommunication); PKO has no native class for a delivered artifact instance.
-- ----------------------------------------------------------------------------
CREATE TABLE IF NOT EXISTS delivered_communications (
  delivered_communication_id          TEXT                 PRIMARY KEY          -- Stored logical identifier for one DeliveredCommunications row.
);
ALTER TABLE delivered_communications ADD COLUMN IF NOT EXISTS procedure_execution TEXT;             -- The run that produced this delivery.
ALTER TABLE delivered_communications ADD COLUMN IF NOT EXISTS sending_step_execution TEXT;          -- The policy-07 step execution that sent it.
ALTER TABLE delivered_communications ADD COLUMN IF NOT EXISTS authorizing_step_execution TEXT;      -- The human approval gate execution that authorized this content. Null means nobody approved it.
ALTER TABLE delivered_communications ADD COLUMN IF NOT EXISTS message_template TEXT;                -- The approved template this delivery was rendered from.
ALTER TABLE delivered_communications ADD COLUMN IF NOT EXISTS channel TEXT;                         -- Email or SMS.
ALTER TABLE delivered_communications ADD COLUMN IF NOT EXISTS recipient_key TEXT;                   -- Opaque recipient identifier; no personal data in the rulebook.
ALTER TABLE delivered_communications ADD COLUMN IF NOT EXISTS sent_at TIMESTAMPTZ;                  -- When the message was dispatched.
ALTER TABLE delivered_communications ADD COLUMN IF NOT EXISTS rendered_content_hash TEXT;           -- Hash of the exact bytes delivered, for comparison against the approved rendering.
ALTER TABLE delivered_communications ADD COLUMN IF NOT EXISTS approved_content_hash TEXT;           -- Hash of the content as it stood at the approval gate.
ALTER TABLE delivered_communications ADD COLUMN IF NOT EXISTS delivery_status TEXT;                 -- Provider-reported delivery outcome.
ALTER TABLE delivered_communications ADD COLUMN IF NOT EXISTS semantic_type_iri TEXT;               -- Extension class IRI.
COMMENT ON TABLE delivered_communications IS 'Everything above is a proxy for the real question, which is instance-level: THIS message, to THIS recipient, rendered from THIS template, authorized by THIS approval. The model has MessageTemplates and CommunicationPolicies as specifications and no record of a single thing ever sent. Without an instance table, ''can I show that what was sent matched what I approved'' is permanently unanswerable rather than merely unanswered — and it is the question a disputing employee actually asks. Extension term (urn:effortless:pko-extension#DeliveredCommunication); PKO has no native class for a delivered artifact instance.';
COMMENT ON COLUMN delivered_communications.delivered_communication_id IS 'Stored logical identifier for one DeliveredCommunications row.';
COMMENT ON COLUMN delivered_communications.procedure_execution IS 'The run that produced this delivery.';
COMMENT ON COLUMN delivered_communications.sending_step_execution IS 'The policy-07 step execution that sent it.';
COMMENT ON COLUMN delivered_communications.authorizing_step_execution IS 'The human approval gate execution that authorized this content. Null means nobody approved it.';
COMMENT ON COLUMN delivered_communications.message_template IS 'The approved template this delivery was rendered from.';
COMMENT ON COLUMN delivered_communications.channel IS 'Email or SMS.';
COMMENT ON COLUMN delivered_communications.recipient_key IS 'Opaque recipient identifier; no personal data in the rulebook.';
COMMENT ON COLUMN delivered_communications.sent_at IS 'When the message was dispatched.';
COMMENT ON COLUMN delivered_communications.rendered_content_hash IS 'Hash of the exact bytes delivered, for comparison against the approved rendering.';
COMMENT ON COLUMN delivered_communications.approved_content_hash IS 'Hash of the content as it stood at the approval gate.';
COMMENT ON COLUMN delivered_communications.delivery_status IS 'Provider-reported delivery outcome.';
COMMENT ON COLUMN delivered_communications.semantic_type_iri IS 'Extension class IRI.';

