COMMENT ON TABLE attestations IS 'Attestations (added by witness loop 2).';
COMMENT ON COLUMN attestations.attestation_id IS 'Primary key of a signature event: one person, one execution, one instant.';
COMMENT ON COLUMN attestations.procedure_execution IS 'The execution being attested to.';
COMMENT ON COLUMN attestations.signed_by_agent IS 'The human who signed.';
COMMENT ON COLUMN attestations.signed_at IS 'The instant of signature.';
COMMENT ON COLUMN attestations.assurance_grade_at_signing IS 'The AssuranceGrade string as the model reported it at the moment of signature, captured then and never recomputed.';
COMMENT ON COLUMN attestations.version_was_fit_at_signing IS 'Whether the executed procedure version was fit to execute at the moment of signature.';

